class VirtualBlockTable:
    def __init__(self):
        self.table = {}
    def allocate_page(self, logical_idx, physical_idx):
        self.table[logical_idx] = physical_idx
    def get_physical(self, logical_idx):
        return self.table.get(logical_idx, -1)

if __name__ == '__main__':
    print('Virtual page table initialized.')
